import{_ as a,o as t,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Conversion Value Mapping Partner API","description":"","frontmatter":{"title":"Conversion Value Mapping Partner API","slug":"conversion-value-mapping-partner-api"},"headers":[],"relativePath":"developer-hub/conversion-value-mapping-partner-api.md","filePath":"developer-hub/conversion-value-mapping-partner-api.md"}'),s={name:"developer-hub/conversion-value-mapping-partner-api.md"};function i(p,e,o,l,c,h){return t(),n("div",null,[...e[0]||(e[0]=[r(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>If you have opted-in to use <a href="https://help.branch.io/using-branch/docs/enable-skadnetwork" target="_blank" rel="noreferrer">SKAdNetwork with Branch</a>, the Branch SDK will call the two necessary Apple methods for SKAdNetwork to enable postbacks to ad partners on your behalf. Conversion values are mapped with your highest value conversion events sent to Branch via the SDK. These mappings are accessed by ad networks for reporting through Branch&#39;s SKAdNetwork Partner API.</p><p>For this, we will utilize a JSON Web Token (JWT), an open standard (<a href="https://tools.ietf.org/html/rfc7519" target="_blank" rel="noreferrer">RFC 7519</a>) that defines a compact and self-contained way for securely transmitting information between parties as a JSON object.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to start using Branch&#39;s SKAdNetwork Partner API, you need the following:</p><ol><li><p>IT/Developer resources for generating access tokens and making API calls.</p></li><li><p><a href="https://help.branch.io/using-branch/docs/enable-skadnetwork" target="_blank" rel="noreferrer">Enabled SKAdNetwork via Branch SDK</a>.</p></li><li><p>Ad Partner that is fetching the conversion value mappings using Partner API is enabled for your Branch account.</p><ol><li>Contact <a href="./submit-a-ticket.html">Branch Support</a>.</li></ol></li></ol><h2 id="share-client-credentials-ad-partner" tabindex="-1">Share Client Credentials Ad Partner <a class="header-anchor" href="#share-client-credentials-ad-partner" aria-label="Permalink to &quot;Share Client Credentials Ad Partner&quot;">​</a></h2><h3 id="_1-request-ad-partner-public-key" tabindex="-1">1. Request Ad Partner Public Key <a class="header-anchor" href="#_1-request-ad-partner-public-key" aria-label="Permalink to &quot;1. Request Ad Partner Public Key&quot;">​</a></h3><p>Create a public key that Branch will use to share the encrypted API credentials for the Ad Partner</p><ol><li><p>Generate a public key using GPG:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gpg --gen-key</span></span></code></pre></div></li><li><p>Export the public key:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gpg --armor --output file-enc-pubkey.txt --export &#39;{{key_uid}}&#39;</span></span></code></pre></div></li><li><p>Send the <code>file-enc-pub.txt</code> and <code>key_uid</code> to <a href="./submit-a-ticket.html">Branch Support</a>.</p></li></ol><h3 id="_2-decrypt-credentials" tabindex="-1">2. Decrypt Credentials <a class="header-anchor" href="#_2-decrypt-credentials" aria-label="Permalink to &quot;2. Decrypt Credentials&quot;">​</a></h3><p>After providing the Public Key to Branch support, they will create and encrypt an API Credentials file that will be sent to you. Once you have the credentials, decrypt it using gpg:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gpg --output api-creds.txt --decrypt api-creds.txt.gpg</span></span></code></pre></div><h3 id="_3-generate-jwt-access-token" tabindex="-1">3. Generate JWT Access Token <a class="header-anchor" href="#_3-generate-jwt-access-token" aria-label="Permalink to &quot;3. Generate JWT Access Token&quot;">​</a></h3><p>Using the credentials from decrypting, generate an access token for Branch SKAdNetwork Partner API with daily validity:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -X POST \\</span></span>
<span class="line"><span>  https://branchmetrics.onelogin.com/oidc/2/token \\</span></span>
<span class="line"><span>  -H &#39;Authorization: Basic &lt;base64 encoded client_id:client_secret&gt;&#39; \\</span></span>
<span class="line"><span>  -H &#39;Content-Type: application/x-www-form-urlencoded&#39; \\</span></span>
<span class="line"><span>  -d &#39;grant_type=client_credentials&amp;resource=https://auth.branch.io/services/partners-api&amp;scope=https://api.branch.io/auth/scopes/{PARTNER_3P}/conversion_value_mappings.read&#39;</span></span></code></pre></div><h2 id="_4-call-the-branch-conversion-value-mapping-partner-api" tabindex="-1">4. Call the Branch Conversion Value Mapping Partner API <a class="header-anchor" href="#_4-call-the-branch-conversion-value-mapping-partner-api" aria-label="Permalink to &quot;4. Call the Branch Conversion Value Mapping Partner API&quot;">​</a></h2><p>Now you can call the Branch Conversion Value Mappings API with the provided access token:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -X GET \\</span></span>
<span class="line"><span>  &#39;http://api2.branch.io/v3/partners/&lt;partner_3P&gt;/conversion-value-mappings?app_id=&lt;iTunesId&gt;&#39; \\</span></span>
<span class="line"><span>  -H &#39;Authorization: Bearer {ACCESS_TOKEN}&#39;</span></span></code></pre></div><p>Please note that the <code>/v3/partners/</code> endpoint will work for SKAN 4.0 as well as SKAN 3.0 and below.</p>`,20)])])}const g=a(s,[["render",i]]);export{u as __pageData,g as default};
